import{_ as n,C as l,o as s,c as o,E as i,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Lithuania Healthcare & HRT","description":"Transgender healthcare access in Lithuania","frontmatter":{"layout":"doc","title":"Lithuania Healthcare & HRT","description":"Transgender healthcare access in Lithuania"},"headers":[],"relativePath":"europe/lithuania/healthcare.md","filePath":"europe/lithuania/healthcare.md","lastUpdated":null}'),c={name:"europe/lithuania/healthcare.md"};function h(u,t,p,m,g,b){const e=l("Badge");return s(),o("div",null,[i(e,{variant:"red"},{default:a(()=>[...t[0]||(t[0]=[r("Very Limited Services",-1)])]),_:1}),i(e,{variant:"yellow"},{default:a(()=>[...t[1]||(t[1]=[r("Santaros Clinics (Vilnius)",-1)])]),_:1}),i(e,{variant:"green"},{default:a(()=>[...t[2]||(t[2]=[r("EU Prescription Portability",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="healthcare-hrt-in-lithuania" tabindex="-1">Healthcare &amp; HRT in Lithuania <a class="header-anchor" href="#healthcare-hrt-in-lithuania" aria-label="Permalink to &quot;Healthcare &amp; HRT in Lithuania&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Lithuania has <strong>very limited</strong> transgender healthcare services:</p><ul><li><strong>Psychiatric diagnosis required</strong> at the only recognized gender clinic</li><li><strong>Real-life experience and HRT required</strong> before surgery can be considered</li><li>Services concentrated in <strong>Vilnius</strong> at Santaros Clinics</li><li>Nearly no options outside the capital</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-referral" tabindex="-1">Step 1: Referral <a class="header-anchor" href="#step-1-referral" aria-label="Permalink to &quot;Step 1: Referral&quot;">​</a></h3><ul><li>Contact <strong>Santaros Clinics</strong> (Vilniaus Santaros Klinikos) Psychiatry Department</li><li>GP referral recommended but direct self-referral sometimes accepted</li><li>Very limited appointment availability (4-8 month wait times)</li></ul><h3 id="step-2-psychiatric-assessment" tabindex="-1">Step 2: Psychiatric Assessment <a class="header-anchor" href="#step-2-psychiatric-assessment" aria-label="Permalink to &quot;Step 2: Psychiatric Assessment&quot;">​</a></h3><ul><li>Diagnosis of gender dysphoria per ICD-10/11</li><li>Multiple sessions (typically 3-6) over several months</li><li>Must demonstrate consistent gender identity and treatment commitment</li></ul><h3 id="step-3-hormone-therapy" tabindex="-1">Step 3: Hormone Therapy <a class="header-anchor" href="#step-3-hormone-therapy" aria-label="Permalink to &quot;Step 3: Hormone Therapy&quot;">​</a></h3><ul><li>Referral to an endocrinologist at Santaros Clinics</li><li>Baseline blood tests required</li><li>HRT prescribed and monitored by the clinic</li><li>Follow-up every 3-6 months</li><li>Public healthcare covers basic HRT medications</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Santaros Clinics (Vilnius University Hospital)</td><td>Vilnius</td><td>Only recognized gender clinic</td></tr><tr><td>Lithuanian University of Health Sciences (LSMU)</td><td>Kaunas</td><td>Limited endocrinology</td></tr><tr><td>Private psychiatrists</td><td>Vilnius, Kaunas</td><td>Assessment (shorter wait times)</td></tr><tr><td>Private endocrinologists</td><td>Vilnius</td><td>HRT (limited trans experience)</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Lithuania under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be re-evaluated by a Lithuanian doctor</li><li><strong>Importing medication</strong>: 3-month supply permitted with a doctor&#39;s letter</li><li><strong>Limited stock</strong>: Some HRT medications may need to be ordered from abroad</li><li><strong>Pharmacies</strong>: Major chains (Euro vaistinė, Gintarinė vaistinė) in cities</li><li><strong>Generic names</strong>: Know your medications&#39; generic names for local equivalents</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li><strong>No gender-affirming surgeries available</strong> in Lithuania</li><li>Previously performed at Santaros Clinics but discontinued</li><li>All surgeries require travel abroad (Thailand, Germany, Serbia, Belgium)</li><li>Theoretical possibility of public funding for abroad surgery is rarely approved</li><li>Most pay out-of-pocket</li><li>Top surgery abroad: €4,000-8,000</li><li>Bottom surgery abroad: €15,000-25,000</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Lithuanian Resident</th><th>Non-Resident</th></tr></thead><tbody><tr><td>Psychiatric assessment</td><td>Free (public)</td><td>€80-120</td></tr><tr><td>Endocrinology visit</td><td>Free (public)</td><td>€60-100</td></tr><tr><td>HRT (monthly)</td><td>€10-30</td><td>€20-50</td></tr><tr><td>Santaros consultation</td><td>Free (public)</td><td>€100-150</td></tr><tr><td>Surgery abroad</td><td>Not covered</td><td>N/A</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.santaros-klinikos.lt/" target="_blank" rel="noreferrer">Santaros Clinics</a></li><li><a href="https://sam.lrv.lt/" target="_blank" rel="noreferrer">Lithuanian Ministry of Health</a></li><li><a href="https://www.lgl.lt/" target="_blank" rel="noreferrer">LGL (National LGBT Rights Organization)</a></li><li><a href="https://transautonomija.lt/" target="_blank" rel="noreferrer">Trans Autonomija</a></li></ul>',21))])}const v=n(c,[["render",h]]);export{f as __pageData,v as default};
